// ============================================================
// GAME LOGIC – pure functions, easy to verify
// ============================================================
function computeRound(players, inputs) {
  // players: [{id, name, totalScore, ...}]
  // inputs:  { [playerId]: { roundScore, calledFae } }
  const entries = players.map(p => {
    const inp = inputs[p.id] || { roundScore: 0, calledFae: false };
    return {
      playerId: p.id,
      roundScore: Number(inp.roundScore) || 0,
      calledFae: !!inp.calledFae,
    };
  });

  const minRoundScore = Math.min(...entries.map(e => e.roundScore));

  return entries.map(e => {
    const player = players.find(p => p.id === e.playerId);
    const penalty = e.calledFae && e.roundScore > minRoundScore ? 5 : 0;
    let newTotal = player.totalScore + e.roundScore + penalty;
    const events = [];

    if (e.calledFae) events.push("FAE_CALLED");
    if (penalty > 0) events.push("PENALTY_ADDED");

    if (newTotal === 100) {
      newTotal = 50;
      events.push("EXACT_100_HALVED");
    }
    if (newTotal >= 101) {
      events.push("PLAYER_LOST");
    }

    const isRoundWinner = e.roundScore === minRoundScore;

    return {
      ...e,
      penalty,
      newTotal,
      isRoundWinner,
      events,
    };
  });
}

function validateInputs(players, inputs) {
  for (const p of players) {
    const inp = inputs[p.id];
    if (!inp || inp.roundScore === "" || inp.roundScore === null || inp.roundScore === undefined) {
      return { ok: false, error: `Punkte für ${p.name} fehlen` };
    }
    const n = Number(inp.roundScore);
    if (Number.isNaN(n) || n < 0) {
      return { ok: false, error: `Ungültige Punkte für ${p.name}` };
    }
  }
  return { ok: true };
}

