// ----- 2. SETUP -----
function SetupScreen({ onBack, onStart }) {
  const [players, setPlayers] = useState([
    { name: "", colorIdx: 0 },
    { name: "", colorIdx: 1 },
  ]);

  function updateName(i, name) {
    setPlayers(prev => prev.map((p, idx) => idx === i ? { ...p, name } : p));
  }
  function addPlayer() {
    if (players.length >= 8) return;
    const usedColors = new Set(players.map(p => p.colorIdx));
    let colorIdx = 0;
    for (let i = 0; i < PLAYER_COLORS.length; i++) {
      if (!usedColors.has(i)) { colorIdx = i; break; }
    }
    setPlayers(prev => [...prev, { name: "", colorIdx }]);
  }
  function removePlayer(i) {
    if (players.length <= 2) return;
    setPlayers(prev => prev.filter((_, idx) => idx !== i));
  }

  const canStart = players.length >= 2 && players.length <= 8 &&
                   players.every(p => p.name.trim().length > 0);

  function handleStart() {
    const finalPlayers = players.map((p, idx) => ({
      id: `p_${Date.now()}_${idx}`,
      name: p.name.trim(),
      colorHex: PLAYER_COLORS[p.colorIdx].hex,
      colorSoft: PLAYER_COLORS[p.colorIdx].soft,
      totalScore: 0,
      isActive: true,
    }));
    onStart(finalPlayers);
  }

  return (
    <div
      className="relative z-10 min-h-screen px-5 max-w-md mx-auto"
      style={{
        paddingTop: "calc(env(safe-area-inset-top) + 32px)",
        paddingBottom: "calc(env(safe-area-inset-bottom) + 32px)",
      }}
    >
      <div className="flex items-center justify-between mb-8">
        <button onClick={onBack} className="p-2 -ml-2" style={{ color: COLORS.textDim, filter: ICON_DROP_SHADOW }}>
          <ChevronLeft size={24} />
        </button>
      </div>

      <h2
        className="text-3xl font-bold mb-2"
        style={{
          fontFamily: "Orbitron, monospace",
          color: "#fff",
          letterSpacing: "0.02em",
          textShadow: TEXT_SHADOW_HEAVY,
        }}
      >
        Teilnehmer
      </h2>
      <p
        className="text-sm mb-8"
        style={{ color: COLORS.textDim, textShadow: TEXT_SHADOW_SOFT }}
      >
        für 2 – 8 Spieler
      </p>

      <div className="space-y-3 mb-6">
        {players.map((p, i) => {
          const color = PLAYER_COLORS[p.colorIdx];
          return (
            <GlassCard key={i} accent={color.hex}>
              <div className="flex items-center gap-3 p-3">
                <div
                  className="w-12 h-12 rounded-xl flex items-center justify-center shrink-0 font-black text-lg"
                  style={{
                    background: color.soft,
                    border: `1px solid ${color.hex}55`,
                    color: color.hex,
                    fontFamily: "Orbitron, monospace",
                    boxShadow: SHADOW_SMALL,
                    textShadow: TEXT_SHADOW_SOFT,
                  }}
                >
                  {String(i + 1).padStart(2, "0")}
                </div>
                <input
                  type="text"
                  value={p.name}
                  onChange={(e) => updateName(i, e.target.value)}
                  placeholder={`Spieler:in ${i + 1}`}
                  className="flex-1 bg-transparent border-0 outline-none text-base"
                  style={{
                    color: "#fff",
                    fontFamily: "Inter, system-ui, sans-serif",
                    textShadow: TEXT_SHADOW_SOFT,
                  }}
                />
                {players.length > 2 && (
                  <button
                    onClick={() => removePlayer(i)}
                    className="p-2 rounded-lg transition-all active:scale-90"
                    style={{ color: COLORS.textFaint, filter: ICON_DROP_SHADOW }}
                  >
                    <X size={18} />
                  </button>
                )}
              </div>
            </GlassCard>
          );
        })}
      </div>

      {players.length < 8 && (
        <button
          onClick={addPlayer}
          className="w-full py-4 rounded-2xl flex items-center justify-center gap-2 mb-8 transition-all active:scale-[0.99]"
          style={{
            background: "rgba(15,5,10,0.5)",
            border: `1px dashed ${COLORS.borderStrong}`,
            color: COLORS.textDim,
            fontFamily: "Inter, system-ui, sans-serif",
            backdropFilter: "blur(12px)",
            WebkitBackdropFilter: "blur(12px)",
            boxShadow: SHADOW_BOX,
            textShadow: TEXT_SHADOW_SOFT,
          }}
        >
          <Plus size={18} /> Spieler:in hinzufügen
        </button>
      )}

      <PrimaryButton onClick={handleStart} disabled={!canStart}>
        <span className="flex items-center justify-center gap-2">
          Runde 1 starten
          <ArrowRight size={18} />
        </span>
      </PrimaryButton>
    </div>
  );
}

// ----- 3. GAME / SCORE INPUT -----
function GameScreen({ players, rounds, onSaveRound, onShowHistory, onQuit }) {
  const roundIndex = rounds.length + 1;
  const [inputs, setInputs] = useState(() => {
    const init = {};
    players.forEach(p => init[p.id] = { roundScore: "", calledFae: false });
    return init;
  });
  const [pulse, setPulse] = useState(null); // playerId pulsing on FAE toggle

  // reset inputs when round changes
  useEffect(() => {
    const init = {};
    players.forEach(p => init[p.id] = { roundScore: "", calledFae: false });
    setInputs(init);
  }, [rounds.length, players]);

  function setScore(pid, val) {
    // numeric, 0-99 reasonable range, allow empty
    if (val === "") {
      setInputs(prev => ({ ...prev, [pid]: { ...prev[pid], roundScore: "" } }));
      return;
    }
    const n = parseInt(val, 10);
    if (Number.isNaN(n) || n < 0) return;
    if (n > 999) return;
    setInputs(prev => ({ ...prev, [pid]: { ...prev[pid], roundScore: n } }));
  }
  function adjustScore(pid, delta) {
    const cur = inputs[pid]?.roundScore;
    const n = (typeof cur === "number" ? cur : 0) + delta;
    if (n < 0) return;
    setInputs(prev => ({ ...prev, [pid]: { ...prev[pid], roundScore: n } }));
  }
  function toggleFae(pid) {
    setInputs(prev => ({
      ...prev,
      [pid]: { ...prev[pid], calledFae: !prev[pid]?.calledFae }
    }));
    setPulse(pid);
    setTimeout(() => setPulse(null), 600);
  }

  const validation = validateInputs(players, inputs);

  // compute leader
  const leader = useMemo(() => {
    return [...players].sort((a, b) => a.totalScore - b.totalScore)[0];
  }, [players]);

  function handleSave() {
    if (!validation.ok) return;
    onSaveRound(inputs);
  }

  return (
    <div
      className="relative z-10 min-h-screen"
      style={{ paddingBottom: "calc(env(safe-area-inset-bottom) + 8rem)" }}
    >
      {/* Header */}
      <div
        className="px-5 pb-4 max-w-md mx-auto"
        style={{ paddingTop: "calc(env(safe-area-inset-top) + 16px)" }}
      >
        <div className="flex items-center justify-between mb-3">
          <button
            onClick={onQuit}
            className="text-xs tracking-widest"
            style={{ color: COLORS.textFaint, fontFamily: "Orbitron, monospace", textShadow: TEXT_SHADOW_SOFT }}
          >
            ✕ ABBRECHEN
          </button>
          <button
            onClick={onShowHistory}
            disabled={rounds.length === 0}
            className="text-xs tracking-widest flex items-center gap-1.5"
            style={{
              color: rounds.length === 0 ? COLORS.textFaint : COLORS.green,
              fontFamily: "Orbitron, monospace",
              opacity: rounds.length === 0 ? 0.4 : 1,
              textShadow: TEXT_SHADOW_SOFT,
            }}
          >
            <Activity size={12} /> VERLAUF
          </button>
        </div>
        <div className="flex items-end justify-between">
          <div>
            <div
              className="text-xs tracking-[0.4em] mb-1"
              style={{ color: COLORS.pink, fontFamily: "Orbitron, monospace", textShadow: TEXT_SHADOW_SOFT }}
            >
              RUNDE
            </div>
            <div
              className="text-6xl font-black leading-none"
              style={{ fontFamily: "Orbitron, monospace", color: "#fff", textShadow: TEXT_SHADOW_HEAVY }}
            >
              {String(roundIndex).padStart(2, "0")}
            </div>
          </div>
          {leader && rounds.length > 0 && (
            <div className="text-right">
              <div className="text-xs tracking-widest mb-1" style={{ color: COLORS.textFaint, fontFamily: "Orbitron, monospace", textShadow: TEXT_SHADOW_SOFT }}>
                FÜHREND
              </div>
              <div className="flex items-center gap-1.5 justify-end">
                <Crown size={14} style={{ color: COLORS.green, filter: ICON_DROP_SHADOW }} />
                <span style={{ color: "#fff", fontWeight: 600, textShadow: TEXT_SHADOW_SOFT }}>{leader.name}</span>
              </div>
              <div
                className="text-2xl font-black"
                style={{ fontFamily: "Orbitron, monospace", color: COLORS.green, textShadow: TEXT_SHADOW_HEAVY }}
              >
                {leader.totalScore}
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Player Cards */}
      <div className="px-5 max-w-md mx-auto space-y-3">
        {players.map(p => {
          const inp = inputs[p.id] || { roundScore: "", calledFae: false };
          const isPulsing = pulse === p.id;
          const danger = p.totalScore >= 90;

          return (
            <GlassCard
              key={p.id}
              accent={inp.calledFae ? COLORS.pink : p.colorHex}
              style={{
                transform: isPulsing ? "scale(1.01)" : "scale(1)",
                transition: "transform 0.3s",
              }}
            >
              <div className="p-4">
                {/* Top row: name + total + FAE toggle */}
                <div className="flex items-center justify-between mb-4">
                  <div className="flex items-center gap-3 flex-1 min-w-0">
                    <div
                      className="w-1 h-12 rounded-full shrink-0"
                      style={{
                        background: p.colorHex,
                        boxShadow: `0 0 12px ${p.colorHex}88, 0 2px 6px rgba(0,0,0,0.4)`,
                      }}
                    />
                    <div className="min-w-0">
                      <div
                        className="font-semibold text-base truncate"
                        style={{ color: "#fff", textShadow: TEXT_SHADOW_SOFT }}
                      >
                        {p.name}
                      </div>
                      <div className="flex items-center gap-2">
                        <span
                          className="text-2xl font-black leading-none"
                          style={{
                            fontFamily: "Orbitron, monospace",
                            color: danger ? COLORS.pink : "#fff",
                            textShadow: TEXT_SHADOW_HEAVY,
                          }}
                        >
                          {p.totalScore}
                        </span>
                        <span
                          className="text-xs"
                          style={{ color: COLORS.textFaint, textShadow: TEXT_SHADOW_SOFT }}
                        >
                          / 100
                        </span>
                        {danger && (
                          <span
                            className="text-[10px] px-1.5 py-0.5 rounded tracking-widest font-bold"
                            style={{
                              background: COLORS.pink + "22",
                              color: COLORS.pink,
                              fontFamily: "Orbitron, monospace",
                              boxShadow: SHADOW_SMALL,
                              textShadow: TEXT_SHADOW_SOFT,
                            }}
                          >
                            DANGER
                          </span>
                        )}
                      </div>
                    </div>
                  </div>
                  <FaeLogoToggle
                    active={inp.calledFae}
                    onToggle={() => toggleFae(p.id)}
                    size={52}
                  />
                </div>

                {/* Score input */}
                <div className="flex items-center gap-2">
                  <button
                    onClick={() => adjustScore(p.id, -1)}
                    className="w-11 h-11 rounded-xl flex items-center justify-center transition-all active:scale-90"
                    style={{
                      background: "rgba(15,5,10,0.55)",
                      border: `1px solid ${COLORS.border}`,
                      color: COLORS.textDim,
                      boxShadow: SHADOW_SMALL,
                    }}
                  >
                    <Minus size={16} />
                  </button>
                  <div
                    className="flex-1 h-11 rounded-xl flex items-center justify-center relative"
                    style={{
                      background: "rgba(15,5,10,0.55)",
                      border: `1px solid ${inp.roundScore !== "" ? p.colorHex + "44" : COLORS.border}`,
                      boxShadow: SHADOW_SMALL,
                    }}
                  >
                    <input
                      type="number"
                      inputMode="numeric"
                      value={inp.roundScore}
                      onChange={(e) => setScore(p.id, e.target.value)}
                      placeholder="–"
                      className="w-full h-full bg-transparent text-center font-bold border-0 outline-none"
                      style={{
                        color: "#fff",
                        fontFamily: "Orbitron, monospace",
                        fontSize: "20px",
                        WebkitAppearance: "none",
                        MozAppearance: "textfield",
                        textShadow: TEXT_SHADOW_HEAVY,
                      }}
                    />
                    <span
                      className="absolute right-3 text-[10px] tracking-widest pointer-events-none"
                      style={{
                        color: COLORS.textFaint,
                        fontFamily: "Orbitron, monospace",
                        textShadow: TEXT_SHADOW_SOFT,
                      }}
                    >
                      PTS
                    </span>
                  </div>
                  <button
                    onClick={() => adjustScore(p.id, 1)}
                    className="w-11 h-11 rounded-xl flex items-center justify-center transition-all active:scale-90"
                    style={{
                      background: "rgba(15,5,10,0.55)",
                      border: `1px solid ${COLORS.border}`,
                      color: COLORS.textDim,
                      boxShadow: SHADOW_SMALL,
                    }}
                  >
                    <Plus size={16} />
                  </button>
                </div>

                {inp.calledFae && (
                  <div
                    className="mt-3 px-3 py-2 rounded-lg text-xs flex items-center gap-2"
                    style={{
                      background: COLORS.pink + "22",
                      border: `1px solid ${COLORS.pink}55`,
                      color: COLORS.pinkBright,
                      boxShadow: SHADOW_SMALL,
                      textShadow: TEXT_SHADOW_SOFT,
                    }}
                  >
                    <Zap size={12} />
                    <span style={{ fontFamily: "Inter, system-ui, sans-serif" }}>
                      <strong>FAE angesagt.</strong> Bei nicht-niedrigster Punktzahl: <strong>+5</strong>
                    </span>
                  </div>
                )}
              </div>
            </GlassCard>
          );
        })}
      </div>

      {/* Bottom action bar */}
      <div
        className="fixed bottom-0 left-0 right-0 z-20"
        style={{
          background: "linear-gradient(180deg, transparent 0%, rgba(21,5,11,0.85) 30%, rgba(21,5,11,0.98) 100%)",
          backdropFilter: "blur(12px)",
          WebkitBackdropFilter: "blur(12px)",
          paddingBottom: "env(safe-area-inset-bottom)",
        }}
      >
        <div className="px-5 pt-8 pb-5 max-w-md mx-auto">
          <PrimaryButton onClick={handleSave} disabled={!validation.ok}>
            <span className="flex items-center justify-center gap-2">
              {validation.ok ? (
                <>Runde {roundIndex} speichern <Check size={18} /></>
              ) : (
                <>{validation.error || "Punkte eintragen"}</>
              )}
            </span>
          </PrimaryButton>
        </div>
      </div>
    </div>
  );
}

// ----- 4. ROUND SUMMARY MODAL -----
function RoundSummary({ players, results, roundIndex, onContinue }) {
  const sorted = [...results].sort((a, b) => a.roundScore - b.roundScore);

  return (
    <div
      className="fixed inset-0 z-50 flex items-end sm:items-center justify-center p-4"
      style={{ background: "rgba(0,0,0,0.7)", backdropFilter: "blur(8px)" }}
    >
      <div className="w-full max-w-md">
        <GlassCard
          style={{
            background: "linear-gradient(180deg, rgba(31,10,18,0.92) 0%, rgba(15,5,10,0.95) 100%)",
          }}
        >
          <div className="p-6">
            <div className="text-center mb-5">
              <div
                className="text-xs tracking-[0.4em] mb-1"
                style={{ color: COLORS.green, fontFamily: "Orbitron, monospace", textShadow: TEXT_SHADOW_SOFT }}
              >
                RUNDE {String(roundIndex).padStart(2, "0")} ABGESCHLOSSEN
              </div>
              <h3
                className="text-3xl font-black"
                style={{ fontFamily: "Orbitron, monospace", color: "#fff", textShadow: TEXT_SHADOW_HEAVY }}
              >
                Ergebnis
              </h3>
            </div>

            <div className="space-y-2 mb-5">
              {sorted.map((r, idx) => {
                const player = players.find(p => p.id === r.playerId);
                const isWinner = r.isRoundWinner;
                const halved = r.events.includes("EXACT_100_HALVED");
                const lost = r.events.includes("PLAYER_LOST");

                return (
                  <div
                    key={r.playerId}
                    className="rounded-2xl p-3 flex items-center gap-3"
                    style={{
                      background: isWinner
                        ? COLORS.green + "12"
                        : lost
                        ? COLORS.pink + "15"
                        : "rgba(15,5,10,0.5)",
                      border: `1px solid ${isWinner ? COLORS.green + "44" : lost ? COLORS.pink + "44" : COLORS.border}`,
                      boxShadow: SHADOW_SMALL,
                    }}
                  >
                    <div
                      className="w-9 h-9 rounded-lg flex items-center justify-center text-xs font-black shrink-0"
                      style={{
                        background: player.colorSoft,
                        color: player.colorHex,
                        fontFamily: "Orbitron, monospace",
                        boxShadow: SHADOW_SMALL,
                        textShadow: TEXT_SHADOW_SOFT,
                      }}
                    >
                      #{idx + 1}
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-1.5">
                        <span
                          className="font-semibold truncate"
                          style={{ color: "#fff", textShadow: TEXT_SHADOW_SOFT }}
                        >
                          {player.name}
                        </span>
                        {isWinner && <Trophy size={13} style={{ color: COLORS.green, filter: ICON_DROP_SHADOW }} />}
                        {r.calledFae && (
                          <img src={FAE_LOGO} alt="FAE" style={{ height: 12, opacity: r.penalty > 0 ? 0.6 : 1, filter: ICON_DROP_SHADOW }} />
                        )}
                      </div>
                      <div
                        className="flex items-center gap-2 text-xs"
                        style={{ color: COLORS.textDim, textShadow: TEXT_SHADOW_SOFT }}
                      >
                        <span>+{r.roundScore}</span>
                        {r.penalty > 0 && (
                          <span style={{ color: COLORS.pink, fontWeight: 600 }}>+{r.penalty} STRAFE</span>
                        )}
                        {halved && (
                          <span style={{ color: COLORS.green, fontWeight: 600 }}>100→50</span>
                        )}
                        {lost && (
                          <span style={{ color: COLORS.pink, fontWeight: 700 }}>VERLOREN</span>
                        )}
                      </div>
                    </div>
                    <div
                      className="text-2xl font-black"
                      style={{
                        fontFamily: "Orbitron, monospace",
                        color: lost ? COLORS.pink : isWinner ? COLORS.green : "#fff",
                        textShadow: TEXT_SHADOW_HEAVY,
                      }}
                    >
                      {r.newTotal}
                    </div>
                  </div>
                );
              })}
            </div>

            <PrimaryButton onClick={onContinue} color={COLORS.green}>
              <span className="flex items-center justify-center gap-2">
                Nächste Runde <ArrowRight size={18} />
              </span>
            </PrimaryButton>
          </div>
        </GlassCard>
      </div>
    </div>
  );
}

// ----- 5. HISTORY -----
function HistoryScreen({ players, rounds, onClose }) {
  const chartData = useMemo(() => {
    const data = [{ round: "Start", ...Object.fromEntries(players.map(p => [p.name, 0])) }];
    rounds.forEach((round, idx) => {
      const row = { round: `R${idx + 1}` };
      players.forEach(p => {
        const entry = round.entries.find(e => e.playerId === p.id);
        row[p.name] = entry ? entry.newTotal : 0;
      });
      data.push(row);
    });
    return data;
  }, [players, rounds]);

  return (
    <div
      className="relative z-10 min-h-screen px-5 max-w-md mx-auto"
      style={{
        paddingTop: "calc(env(safe-area-inset-top) + 24px)",
        paddingBottom: "calc(env(safe-area-inset-bottom) + 6rem)",
      }}
    >
      <div className="flex items-center justify-between mb-6">
        <button onClick={onClose} className="p-2 -ml-2" style={{ color: COLORS.textDim, filter: ICON_DROP_SHADOW }}>
          <ChevronLeft size={24} />
        </button>
        <div className="text-xs tracking-[0.3em]" style={{ color: COLORS.textFaint, fontFamily: "Orbitron, monospace", textShadow: TEXT_SHADOW_SOFT }}>
          GAME HISTORY
        </div>
      </div>

      <h2 className="text-3xl font-bold mb-1" style={{ fontFamily: "Orbitron, monospace", color: "#fff", textShadow: TEXT_SHADOW_HEAVY }}>
        Verlauf
      </h2>
      <p className="text-sm mb-6" style={{ color: COLORS.textDim, textShadow: TEXT_SHADOW_SOFT }}>
        {rounds.length} {rounds.length === 1 ? "Runde" : "Runden"} gespielt
      </p>

      {/* Chart */}
      <GlassCard className="mb-5">
        <div className="p-4">
          <div className="text-xs tracking-widest mb-3" style={{ color: COLORS.textFaint, fontFamily: "Orbitron, monospace", textShadow: TEXT_SHADOW_SOFT }}>
            PUNKTEVERLAUF
          </div>
          <div style={{ width: "100%", height: 220 }}>
            <ResponsiveContainer>
              <LineChart data={chartData} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.05)" />
                <XAxis dataKey="round" stroke={COLORS.textFaint} fontSize={11} />
                <YAxis stroke={COLORS.textFaint} fontSize={11} domain={[0, "auto"]} />
                <Tooltip
                  contentStyle={{
                    background: COLORS.surface,
                    border: `1px solid ${COLORS.border}`,
                    borderRadius: 12,
                    fontSize: 12,
                  }}
                  labelStyle={{ color: "#fff" }}
                />
                {players.map(p => (
                  <Line
                    key={p.id}
                    type="monotone"
                    dataKey={p.name}
                    stroke={p.colorHex}
                    strokeWidth={2.5}
                    dot={{ fill: p.colorHex, r: 3 }}
                    activeDot={{ r: 5 }}
                  />
                ))}
              </LineChart>
            </ResponsiveContainer>
          </div>
        </div>
      </GlassCard>

      {/* Round-by-round table */}
      <div className="text-xs tracking-widest mb-3 px-1" style={{ color: COLORS.textFaint, fontFamily: "Orbitron, monospace", textShadow: TEXT_SHADOW_SOFT }}>
        ALLE RUNDEN
      </div>
      <div className="space-y-2">
        {[...rounds].reverse().map((round, revIdx) => {
          const realIdx = rounds.length - revIdx;
          return (
            <GlassCard key={round.id}>
              <div className="p-3">
                <div className="flex items-center justify-between mb-2">
                  <div
                    className="text-xs font-black tracking-widest"
                    style={{ color: COLORS.pink, fontFamily: "Orbitron, monospace", textShadow: TEXT_SHADOW_SOFT }}
                  >
                    RUNDE {String(realIdx).padStart(2, "0")}
                  </div>
                </div>
                <div className="space-y-1">
                  {round.entries.map(e => {
                    const p = players.find(pl => pl.id === e.playerId);
                    return (
                      <div key={e.playerId} className="flex items-center gap-2 text-sm" style={{ textShadow: TEXT_SHADOW_SOFT }}>
                        <div className="w-1.5 h-1.5 rounded-full" style={{ background: p.colorHex, boxShadow: `0 0 6px ${p.colorHex}` }} />
                        <span className="flex-1 truncate" style={{ color: "#fff" }}>{p.name}</span>
                        <span style={{ color: COLORS.textDim }}>+{e.roundScore}</span>
                        {e.penalty > 0 && (
                          <span style={{ color: COLORS.pink, fontWeight: 600 }}>+{e.penalty}</span>
                        )}
                        {e.calledFae && (
                          <img src={FAE_LOGO} alt="FAE" style={{ height: 10, opacity: e.penalty > 0 ? 0.5 : 1, filter: ICON_DROP_SHADOW }} />
                        )}
                        {e.events.includes("EXACT_100_HALVED") && (
                          <span className="text-[10px] tracking-widest px-1.5 rounded" style={{ color: COLORS.green, background: COLORS.green + "22", fontFamily: "Orbitron, monospace" }}>100→50</span>
                        )}
                        <span
                          className="font-bold w-10 text-right"
                          style={{ fontFamily: "Orbitron, monospace", color: e.isRoundWinner ? COLORS.green : "#fff", textShadow: TEXT_SHADOW_SOFT }}
                        >
                          {e.newTotal}
                        </span>
                      </div>
                    );
                  })}
                </div>
              </div>
            </GlassCard>
          );
        })}
      </div>
    </div>
  );
}

// ----- 6. END SCREEN -----
function EndScreen({ players, rounds, loserId, onRestart, onQuit }) {
  const loser = players.find(p => p.id === loserId);
  const ranking = useMemo(() => {
    return [...players]
      .map(p => ({ ...p, isLoser: p.id === loserId }))
      .sort((a, b) => {
        if (a.isLoser) return 1;
        if (b.isLoser) return -1;
        return a.totalScore - b.totalScore;
      });
  }, [players, loserId]);
  const winner = ranking[0];

  function shareResult() {
    const text = `🏁 FAE COUNTER\n\n🏆 ${winner.name} gewinnt mit ${winner.totalScore} Punkten\n💀 ${loser.name} verliert (${loser.totalScore})\n\n${rounds.length} Runden gespielt`;
    if (navigator.share) {
      navigator.share({ title: "FAE Counter Ergebnis", text }).catch(() => {});
    } else if (navigator.clipboard) {
      navigator.clipboard.writeText(text);
      alert("Ergebnis in Zwischenablage kopiert!");
    }
  }

  return (
    <div
      className="relative z-10 min-h-screen px-5 max-w-md mx-auto"
      style={{
        paddingTop: "calc(env(safe-area-inset-top) + 32px)",
        paddingBottom: "calc(env(safe-area-inset-bottom) + 32px)",
      }}
    >
      <div
        className="text-xs tracking-[0.4em] text-center mb-2"
        style={{ color: COLORS.pink, fontFamily: "Orbitron, monospace", textShadow: TEXT_SHADOW_SOFT }}
      >
        ◆ GAME OVER ◆
      </div>

      {/* Loser hero */}
      <GlassCard accent={COLORS.pink} className="mb-5">
        <div className="p-6 text-center relative overflow-hidden">
          <div
            className="absolute inset-0 pointer-events-none"
            style={{
              background: `radial-gradient(circle at center, ${COLORS.pink}22 0%, transparent 70%)`,
            }}
          />
          <div className="relative">
            <Skull size={32} style={{ color: COLORS.pink, margin: "0 auto", filter: ICON_DROP_SHADOW }} />
            <div className="text-xs tracking-[0.3em] mt-3" style={{ color: COLORS.textDim, fontFamily: "Orbitron, monospace", textShadow: TEXT_SHADOW_SOFT }}>
              VERLOREN
            </div>
            <h2
              className="text-4xl font-black mt-2 mb-1"
              style={{ fontFamily: "Orbitron, monospace", color: "#fff", textShadow: TEXT_SHADOW_HEAVY }}
            >
              {loser.name}
            </h2>
            <div
              className="text-7xl font-black leading-none mt-3"
              style={{
                fontFamily: "Orbitron, monospace",
                background: `linear-gradient(180deg, ${COLORS.pinkBright} 0%, ${COLORS.pink} 100%)`,
                WebkitBackgroundClip: "text",
                WebkitTextFillColor: "transparent",
                filter: `drop-shadow(0 4px 12px rgba(0,0,0,0.7)) drop-shadow(0 12px 32px ${COLORS.pink}55)`,
              }}
            >
              {loser.totalScore}
            </div>
            <div className="text-xs tracking-widest mt-2" style={{ color: COLORS.textFaint, fontFamily: "Orbitron, monospace", textShadow: TEXT_SHADOW_SOFT }}>
              PUNKTE · 101+ ERREICHT
            </div>
          </div>
        </div>
      </GlassCard>

      {/* Ranking */}
      <div className="text-xs tracking-widest mb-2 px-1" style={{ color: COLORS.textFaint, fontFamily: "Orbitron, monospace", textShadow: TEXT_SHADOW_SOFT }}>
        ENDPLATZIERUNG
      </div>
      <div className="space-y-2 mb-6">
        {ranking.map((p, idx) => (
          <GlassCard
            key={p.id}
            accent={idx === 0 ? COLORS.green : p.isLoser ? COLORS.pink : null}
          >
            <div className="p-3 flex items-center gap-3">
              <div
                className="w-10 h-10 rounded-xl flex items-center justify-center font-black shrink-0"
                style={{
                  background: idx === 0 ? COLORS.green + "22" : p.isLoser ? COLORS.pink + "22" : "rgba(15,5,10,0.5)",
                  color: idx === 0 ? COLORS.green : p.isLoser ? COLORS.pink : COLORS.textDim,
                  fontFamily: "Orbitron, monospace",
                  boxShadow: SHADOW_SMALL,
                  textShadow: TEXT_SHADOW_SOFT,
                }}
              >
                {idx === 0 ? <Crown size={16} style={{ filter: ICON_DROP_SHADOW }} /> : `#${idx + 1}`}
              </div>
              <div className="flex-1 min-w-0">
                <div className="font-semibold truncate" style={{ color: "#fff", textShadow: TEXT_SHADOW_SOFT }}>{p.name}</div>
                <div className="text-xs" style={{ color: COLORS.textFaint, textShadow: TEXT_SHADOW_SOFT }}>
                  {idx === 0 ? "Sieger:in" : p.isLoser ? "Verlierer:in" : `Platz ${idx + 1}`}
                </div>
              </div>
              <div
                className="text-2xl font-black"
                style={{
                  fontFamily: "Orbitron, monospace",
                  color: idx === 0 ? COLORS.green : p.isLoser ? COLORS.pink : "#fff",
                  textShadow: TEXT_SHADOW_HEAVY,
                }}
              >
                {p.totalScore}
              </div>
            </div>
          </GlassCard>
        ))}
      </div>

      {/* Actions */}
      <div className="space-y-3">
        <PrimaryButton onClick={onRestart} color={COLORS.green}>
          <span className="flex items-center justify-center gap-2">
            <RotateCcw size={18} /> Revanche starten
          </span>
        </PrimaryButton>
        <div className="grid grid-cols-2 gap-3">
          <GhostButton onClick={shareResult} className="!w-full">
            <span className="flex items-center justify-center gap-2 text-sm">
              <Share2 size={14} /> Teilen
            </span>
          </GhostButton>
          <GhostButton onClick={onQuit} className="!w-full">
            <span className="flex items-center justify-center gap-2 text-sm">
              Beenden
            </span>
          </GhostButton>
        </div>
      </div>
    </div>
  );
}

// ============================================================
// MAIN APP
// ============================================================
export default function FaeCounter() {
  const [screen, setScreen] = useState("splash"); // splash | setup | game | history | end
  const [players, setPlayers] = useState([]);
  const [rounds, setRounds] = useState([]);
  const [pendingResults, setPendingResults] = useState(null);
  const [loserId, setLoserId] = useState(null);

  function handleStartGame(newPlayers) {
    setPlayers(newPlayers);
    setRounds([]);
    setLoserId(null);
    setScreen("game");
  }

  function handleSaveRound(inputs) {
    const results = computeRound(players, inputs);

    // build round object
    const roundObj = {
      id: `r_${Date.now()}`,
      index: rounds.length + 1,
      createdAt: new Date().toISOString(),
      entries: results,
      events: results.flatMap(r => r.events.map(ev => ({ playerId: r.playerId, type: ev }))),
    };

    // update player totals
    const updatedPlayers = players.map(p => {
      const entry = results.find(e => e.playerId === p.id);
      return { ...p, totalScore: entry.newTotal };
    });

    setPlayers(updatedPlayers);
    setRounds(prev => [...prev, roundObj]);
    setPendingResults({ results, roundIndex: rounds.length + 1 });
  }

  // when user dismisses round summary
  function continueAfterRound() {
    const lostResult = pendingResults.results.find(r => r.events.includes("PLAYER_LOST"));
    if (lostResult) {
      setLoserId(lostResult.playerId);
      setScreen("end");
    }
    setPendingResults(null);
  }

  function restart() {
    setPlayers(prev => prev.map(p => ({ ...p, totalScore: 0 })));
    setRounds([]);
    setLoserId(null);
    setScreen("game");
  }

  function quitToSplash() {
    setPlayers([]);
    setRounds([]);
    setLoserId(null);
    setPendingResults(null);
    setScreen("splash");
  }

  return (
    <div
      className="min-h-screen w-full relative"
      style={{
        background: "#15050b",
        color: "#fff",
        fontFamily: "Inter, system-ui, sans-serif",
      }}
    >
      {/* Inject Google Fonts + custom keyframes */}
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Orbitron:wght@400;500;600;700;800;900&family=Inter:wght@400;500;600;700;800&display=swap');
        @keyframes faePulse {
          0%, 100% { box-shadow: 0 0 0 0 rgba(229,0,75,0.5); }
          50% { box-shadow: 0 0 0 8px rgba(229,0,75,0); }
        }
        @keyframes blobA {
          0%, 100% { transform: translate(0,0) scale(1); }
          33% { transform: translate(45px,-30px) scale(1.12); }
          66% { transform: translate(-25px,40px) scale(0.95); }
        }
        @keyframes blobB {
          0%, 100% { transform: translate(0,0) scale(1); }
          33% { transform: translate(-40px,30px) scale(1.18); }
          66% { transform: translate(30px,-25px) scale(0.92); }
        }
        @keyframes blobC {
          0%, 100% { transform: translate(0,0) scale(1); }
          50% { transform: translate(30px,-50px) scale(1.08); }
        }
        @keyframes blobD {
          0%, 100% { transform: translate(0,0) scale(1); }
          50% { transform: translate(-30px,-30px) scale(1.22); }
        }
        @keyframes blobE {
          0%, 100% { transform: translate(0,0) scale(1); }
          50% { transform: translate(35px,25px) scale(1.1); }
        }
        @keyframes streamFloat {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(-12px); }
        }
        input[type=number]::-webkit-inner-spin-button,
        input[type=number]::-webkit-outer-spin-button {
          -webkit-appearance: none;
          margin: 0;
        }
        body { background: #15050b; }
      `}</style>

      <AmbientBg />

      {screen === "splash" && (
        <SplashScreen onStart={() => setScreen("setup")} />
      )}
      {screen === "setup" && (
        <SetupScreen
          onBack={() => setScreen("splash")}
          onStart={handleStartGame}
        />
      )}
      {screen === "game" && (
        <GameScreen
          players={players}
          rounds={rounds}
          onSaveRound={handleSaveRound}
          onShowHistory={() => setScreen("history")}
          onQuit={quitToSplash}
        />
      )}
      {screen === "history" && (
        <HistoryScreen
          players={players}
          rounds={rounds}
          onClose={() => setScreen("game")}
        />
      )}
      {screen === "end" && loserId && (
        <EndScreen
          players={players}
          rounds={rounds}
          loserId={loserId}
          onRestart={restart}
          onQuit={quitToSplash}
        />
      )}

      {/* Round summary overlay */}
      {pendingResults && (
        <RoundSummary
          players={players}
          results={pendingResults.results}
          roundIndex={pendingResults.roundIndex}
          onContinue={continueAfterRound}
        />
      )}
    </div>
  );
}
